import React, { useState, useRef, useEffect } from "react";
import axios from "axios";
import { motion, AnimatePresence } from "framer-motion";
import "./styles.css";

// التوصيفات البرمجية
interface Candidate {
  id: string;
  name: string;
  match_score: number;
  rerank_score: number;
  skill_score: number;
  final_score: number;
  technical_skills?: string;
}

interface Analysis {
  category: string;
  experience_level: string;
  technical_skills: string[];
  summary: string;
}

const API_BASE_URL = "http://localhost:8000";

export default function App() {
  const [jdText, setJdText] = useState<string>("");
  const [loading, setLoading] = useState<boolean>(false);
  const [results, setResults] = useState<Candidate[]>([]);
  const [analysis, setAnalysis] = useState<Analysis | null>(null);
  const [error, setError] = useState<string>("");

  // حالات لوحة الذكاء الجانبية
  const [selectedCandidate, setSelectedCandidate] = useState<Candidate | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(false);
  const [chatInput, setChatInput] = useState("");
  const [chatMessages, setChatMessages] = useState<{ role: string; text: string }[]>([]);
  const [chatLoading, setChatLoading] = useState(false);

  const startMatching = async () => {
    if (!jdText.trim()) return;
    setError("");
    setLoading(true);
    setResults([]);
    setAnalysis(null);
    setIsPanelOpen(false);

    try {
      const response = await axios.post(`${API_BASE_URL}/search`, {
        job_description: jdText,
        top_k: 10,
      });
      setResults(response.data.candidates);
      setAnalysis(response.data.analysis);
    } catch (err) {
      setError("خطأ في الاتصال بالسيرفر!");
    } finally {
      setLoading(false);
    }
  };

  const openIntelligencePanel = (candidate: Candidate) => {
    setSelectedCandidate(candidate);
    setIsPanelOpen(true);
    // تصفير الشات عند تغيير المرشح لبدء سياق جديد
    setChatMessages([{ role: "ai", text: `تحليل ذكي لـ ${candidate.name}: يمتلك توافق بنسبة ${Math.round(candidate.final_score * 100)}% مع المتطلبات.` }]);
  };

  const handleChat = async () => {
    if (!chatInput.trim() || !selectedCandidate) return;
    const userMsg = chatInput;
    setChatInput("");
    setChatMessages((prev) => [...prev, { role: "user", text: userMsg }]);
    setChatLoading(true);

    try {
      const response = await axios.post(`${API_BASE_URL}/chat`, {
        question: userMsg,
        candidate_ids: [selectedCandidate.id],
        history: [],
      });
      setChatMessages((prev) => [...prev, { role: "ai", text: response.data.answer }]);
    } catch {
      setChatMessages((prev) => [...prev, { role: "ai", text: "حدث خطأ في جلب البيانات." }]);
    } finally {
      setChatLoading(false);
    }
  };

  return (
    <div className="pro-container">
      {/* الهيدر الاحترافي */}
      <header className="main-nav">
        <div className="nav-left">
          <div className="logo-box">ITG</div>
          <div className="divider"></div>
          <span className="app-subtitle">Smart Matcher</span>
        </div>
        <div className="nav-right">
          <div className="system-status">
            <span className="status-dot"></span> AI Engine Online
          </div>
        </div>
      </header>

      <main className="main-content">
        {/* القسم الأيسر: مدخلات الوظيفة */}
        <section className="input-section">
          <div className="glass-card">
            <h2 className="title-gold">Job Intelligence</h2>
            <p className="hint">أدخل وصف الوظيفة لبدء المطابقة العصبية</p>

            <div className="textarea-container">
              <textarea
                value={jdText}
                onChange={(e) => setJdText(e.target.value)}
                placeholder="Paste Job Description here..."
              />
            </div>

            <button 
              className={`pro-button ${loading ? 'loading' : ''}`}
              onClick={startMatching}
              disabled={loading}
            >
              {loading ? "Matching Patterns..." : "Initiate AI Search"}
            </button>
          </div>
        </section>

        {/* القسم الأيمن: نتائج البحث */}
        <section className="results-section">
          <div className="results-grid">
            <AnimatePresence>
              {results.map((cand, idx) => (
                <motion.div
                  key={cand.id}
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ delay: idx * 0.05 }}
                  className="candidate-card"
                  onClick={() => openIntelligencePanel(cand)}
                >
                  <div className="card-top">
                    <span className="rank-badge">#{idx + 1}</span>
                    <div className="match-ring">
                      <svg viewBox="0 0 36 36">
                        <path className="ring-bg" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" />
                        <path className="ring-fill" strokeDasharray={`${cand.final_score * 100}, 100`} d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" />
                      </svg>
                      <span className="ring-text">{Math.round(cand.final_score * 100)}%</span>
                    </div>
                  </div>

                  <div className="card-body">
                    <h3>{cand.name}</h3>
                    <div className="skills-row">
                      {cand.technical_skills?.split(",").slice(0, 3).map(s => (
                        <span key={s} className="skill-tag">{s.trim()}</span>
                      ))}
                    </div>
                  </div>
                  <div className="card-footer">
                    <span className="ai-trigger">Click for AI Insights ◈</span>
                  </div>
                </motion.div>
              ))}
            </AnimatePresence>

            {results.length === 0 && !loading && (
              <div className="empty-state">
                <div className="grid-icon">◈</div>
                <p>Waiting for Input Intelligence...</p>
              </div>
            )}
          </div>
        </section>
      </main>

      {/* لوحة التحليلات الجانبية (Side Intelligence Panel) */}
      <AnimatePresence>
        {isPanelOpen && (
          <>
            <motion.div 
              className="backdrop" 
              onClick={() => setIsPanelOpen(false)}
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            />
            <motion.div 
              className="side-panel"
              initial={{ x: "100%" }} animate={{ x: 0 }} exit={{ x: "100%" }}
              transition={{ type: "spring", damping: 25, stiffness: 200 }}
            >
              <div className="panel-header">
                <h3>Candidate Analysis</h3>
                <button onClick={() => setIsPanelOpen(false)}>✕</button>
              </div>

              <div className="panel-content">
                <div className="candidate-info">
                  <h2>{selectedCandidate?.name}</h2>
                  <p>System Reference: {selectedCandidate?.id}</p>
                </div>

                <div className="chat-box">
                  {chatMessages.map((m, i) => (
                    <div key={i} className={`msg ${m.role}`}>
                      {m.text}
                    </div>
                  ))}
                  {chatLoading && <div className="typing">AI is analyzing...</div>}
                </div>
              </div>

              <div className="panel-footer">
                <input 
                  value={chatInput}
                  onChange={(e) => setChatInput(e.target.value)}
                  placeholder="Ask about this candidate..."
                  onKeyDown={(e) => e.key === "Enter" && handleChat()}
                />
                <button onClick={handleChat}>Send</button>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
}
